#!/usr/bin/env bash
# gen-bench-corpus.sh — assemble the self-contained benchmark corpus files.
#
# Each tools/bench-src/<name>.sml is an algorithm "head" that defines four
# names: bench, checksum, bench_name, default_n. This script concatenates each
# head with the shared driver footer (tools/bench-footer.sml) to produce the
# self-contained tools/diff-corpus/bench_<name>.sml files that the differential
# sweep globs and that tools/bench.sh times. Run after editing any head or the
# footer. Generated files carry a "DO NOT EDIT" banner.
set -euo pipefail
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
SRC="$ROOT/tools/bench-src"
FOOTER="$ROOT/tools/bench-footer.sml"
OUT="$ROOT/tools/diff-corpus"

[ -f "$FOOTER" ] || { echo "missing $FOOTER"; exit 1; }
n=0
for head in "$SRC"/*.sml; do
  name="$(basename "$head" .sml)"
  dst="$OUT/bench_${name}.sml"
  {
    echo "(* GENERATED by tools/gen-bench-corpus.sh from tools/bench-src/${name}.sml"
    echo " * + tools/bench-footer.sml — DO NOT EDIT HERE; edit the source + regenerate. *)"
    cat "$head"
    cat "$FOOTER"
  } > "$dst"
  n=$((n+1))
  echo "wrote $dst"
done
echo "generated $n benchmark corpus file(s)"
